import{b as a}from"./api.BhIwWj_B.js";import{authService as r}from"./auth.h-v8t-lg.js";import"./hoisted.Ds42c_VI.js";const d=document.getElementById("login-form"),t=document.getElementById("error-message"),e=document.getElementById("login-btn");d?.addEventListener("submit",async i=>{i.preventDefault(),e&&(e.classList.add("is-loading"),e.setAttribute("disabled","true")),t?.classList.add("is-hidden");const n=document.getElementById("email")?.value,o=document.getElementById("password")?.value;try{const s=await a.login(n,o);r.setAuth(s.data),window.location.href="/"}catch(s){t&&(t.textContent=s.message||"Error al iniciar sesión",t.classList.remove("is-hidden"))}finally{e&&(e.classList.remove("is-loading"),e.removeAttribute("disabled"))}});
